package dsig

import (
	"os"
	"path/filepath"
	"strings"
	"testing"

	"github.com/beevik/etree"
)

// TestW3CC14NConformance tests the library's canonicalization against reference
// outputs generated by xmllint (libxml2). Each test case has an input XML file
// in testdata/c14n/ and expected outputs for C14N 1.0, C14N 1.1, and Exc-C14N.
//
// Note: xmllint's --c14n/--c14n11/--exc-c14n modes always include comments.
// We compare against our with-comments canonicalizers for an apples-to-apples
// comparison. Comment-stripping is tested separately in TestW3CC14NWithComments.
//
// Any divergence between our output and xmllint's output indicates a spec
// non-compliance that could be exploited for signature forgery.
func TestW3CC14NConformance(t *testing.T) {
	// Known limitations where divergence from xmllint is expected:
	// - attr_whitespace: etree does not perform XML attribute value normalization
	//   (tabs/newlines in attrs remain as &#x9;/&#xA; instead of being normalized
	//   to spaces before C14N). This is an etree parser limitation.
	knownLimitations := map[string]string{
		"attr_whitespace": "etree does not normalize tab/newline in attribute values (parser limitation)",
	}

	type c14nMethod struct {
		name   string
		ext    string // file extension for expected output
		makeC  func() Canonicalizer
	}

	// Use with-comments canonicalizers since xmllint always includes comments
	methods := []c14nMethod{
		{
			name:  "ExcC14N",
			ext:   ".exc-c14n",
			makeC: func() Canonicalizer { return MakeC14N10ExclusiveWithCommentsCanonicalizerWithPrefixList("") },
		},
		{
			name:  "C14N11",
			ext:   ".c14n11",
			makeC: func() Canonicalizer { return MakeC14N11WithCommentsCanonicalizer() },
		},
		{
			name:  "C14N10",
			ext:   ".c14n10",
			makeC: func() Canonicalizer { return MakeC14N10WithCommentsCanonicalizer() },
		},
	}

	// Find all test input files
	files, err := filepath.Glob("testdata/c14n/*.xml")
	if err != nil {
		t.Fatal(err)
	}
	if len(files) == 0 {
		t.Fatal("no test XML files found in testdata/c14n/")
	}

	for _, xmlFile := range files {
		baseName := strings.TrimSuffix(filepath.Base(xmlFile), ".xml")

		for _, method := range methods {
			expectedFile := filepath.Join("testdata/c14n", baseName+method.ext)

			// Skip if no expected output file
			expectedBytes, err := os.ReadFile(expectedFile)
			if err != nil {
				continue
			}
			if len(expectedBytes) == 0 {
				continue
			}

			t.Run(baseName+"/"+method.name, func(t *testing.T) {
				if reason, ok := knownLimitations[baseName]; ok {
					t.Skipf("known limitation: %s", reason)
				}
				inputBytes, err := os.ReadFile(xmlFile)
				if err != nil {
					t.Fatal(err)
				}

				doc := etree.NewDocument()
				if err := doc.ReadFromBytes(inputBytes); err != nil {
					t.Fatalf("failed to parse input XML: %v", err)
				}

				el := doc.Root()
				if el == nil {
					t.Fatal("empty document")
				}

				c := method.makeC()
				got, err := c.Canonicalize(el)
				if err != nil {
					t.Fatalf("Canonicalize failed: %v", err)
				}

				expected := string(expectedBytes)
				actual := string(got)

				if actual != expected {
					t.Errorf("C14N output differs from xmllint reference\n"+
						"--- expected (xmllint) ---\n%s\n"+
						"--- got (goxmldsig) ---\n%s\n"+
						"--- diff ---\n%s",
						expected, actual, diffStrings(expected, actual))
				}
			})
		}
	}
}

// TestW3CC14NWithComments tests canonicalization with comments preserved.
func TestW3CC14NWithComments(t *testing.T) {
	input := `<doc>
 <text>First</text>
 <!-- comment -->
 <text>Second</text>
</doc>`

	tests := []struct {
		name           string
		makeC          func() Canonicalizer
		expectComment  bool
	}{
		{"ExcC14N/NoComments", func() Canonicalizer { return MakeC14N10ExclusiveCanonicalizerWithPrefixList("") }, false},
		{"ExcC14N/WithComments", func() Canonicalizer { return MakeC14N10ExclusiveWithCommentsCanonicalizerWithPrefixList("") }, true},
		{"C14N11/NoComments", func() Canonicalizer { return MakeC14N11Canonicalizer() }, false},
		{"C14N11/WithComments", func() Canonicalizer { return MakeC14N11WithCommentsCanonicalizer() }, true},
		{"C14N10/NoComments", func() Canonicalizer { return MakeC14N10RecCanonicalizer() }, false},
		{"C14N10/WithComments", func() Canonicalizer { return MakeC14N10WithCommentsCanonicalizer() }, true},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			doc := etree.NewDocument()
			if err := doc.ReadFromString(input); err != nil {
				t.Fatal(err)
			}

			c := tt.makeC()
			out, err := c.Canonicalize(doc.Root())
			if err != nil {
				t.Fatal(err)
			}

			hasComment := strings.Contains(string(out), "<!-- comment -->")
			if hasComment != tt.expectComment {
				t.Errorf("comment presence: got %v, want %v\noutput: %s", hasComment, tt.expectComment, string(out))
			}
		})
	}
}

// TestW3CExcC14NNamespacePushdown verifies that exclusive canonicalization
// pushes namespace declarations down to the elements that use them.
func TestW3CExcC14NNamespacePushdown(t *testing.T) {
	tests := []struct {
		name     string
		input    string
		expected string
	}{
		{
			name: "UnusedNamespaceStripped",
			input: `<a xmlns:unused="http://unused" xmlns:used="http://used"><used:b/></a>`,
			expected: `<a><used:b xmlns:used="http://used"></used:b></a>`,
		},
		{
			name: "NamespacePushedToUser",
			input: `<root xmlns:p="http://p"><a><p:b/></a></root>`,
			expected: `<root><a><p:b xmlns:p="http://p"></p:b></a></root>`,
		},
		{
			name: "DefaultNamespacePreserved",
			input: `<root xmlns="http://default"><a><b/></a></root>`,
			expected: `<root xmlns="http://default"><a><b></b></a></root>`,
		},
		{
			name: "AttributeNamespaceIncluded",
			input: `<root xmlns:a="http://a"><elem a:x="1"/></root>`,
			expected: `<root><elem xmlns:a="http://a" a:x="1"></elem></root>`,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			doc := etree.NewDocument()
			if err := doc.ReadFromString(tt.input); err != nil {
				t.Fatal(err)
			}

			c := MakeC14N10ExclusiveCanonicalizerWithPrefixList("")
			got, err := c.Canonicalize(doc.Root())
			if err != nil {
				t.Fatal(err)
			}

			if string(got) != tt.expected {
				t.Errorf("exc-c14n mismatch\nexpected: %s\ngot:      %s", tt.expected, string(got))
			}
		})
	}
}

// TestW3CC14NAttributeSorting verifies that attributes are sorted in canonical
// order: namespace declarations first (sorted by prefix), then remaining
// attributes sorted by namespace URI then local name.
func TestW3CC14NAttributeSorting(t *testing.T) {
	// From W3C C14N 1.0 spec, Section 3.3
	input := `<e5 xmlns:a="http://www.w3.org" a:attr="out" b:attr="sorted" attr2="all" attr="I'm" xmlns:b="http://www.ietf.org"/>`

	// Expected: namespace decls sorted by prefix, then attrs sorted by ns-uri then local
	tests := []struct {
		name     string
		makeC    func() Canonicalizer
		expected string
	}{
		{
			name:     "C14N10",
			makeC:    func() Canonicalizer { return MakeC14N10RecCanonicalizer() },
			expected: `<e5 xmlns:a="http://www.w3.org" xmlns:b="http://www.ietf.org" attr="I'm" attr2="all" b:attr="sorted" a:attr="out"></e5>`,
		},
		{
			name:     "C14N11",
			makeC:    func() Canonicalizer { return MakeC14N11Canonicalizer() },
			expected: `<e5 xmlns:a="http://www.w3.org" xmlns:b="http://www.ietf.org" attr="I'm" attr2="all" b:attr="sorted" a:attr="out"></e5>`,
		},
		{
			name:  "ExcC14N",
			makeC: func() Canonicalizer { return MakeC14N10ExclusiveCanonicalizerWithPrefixList("") },
			// Exc-C14N strips unused namespaces - both a: and b: are used on attrs
			expected: `<e5 xmlns:a="http://www.w3.org" xmlns:b="http://www.ietf.org" attr="I'm" attr2="all" b:attr="sorted" a:attr="out"></e5>`,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			doc := etree.NewDocument()
			if err := doc.ReadFromString(input); err != nil {
				t.Fatal(err)
			}

			c := tt.makeC()
			got, err := c.Canonicalize(doc.Root())
			if err != nil {
				t.Fatal(err)
			}

			if string(got) != tt.expected {
				t.Errorf("attribute sorting mismatch\nexpected: %s\ngot:      %s", tt.expected, string(got))
			}
		})
	}
}

