// TestW3CC14NSpecialCharacters verifies proper escaping of special characters
// in element content and attribute values.
func TestW3CC14NSpecialCharacters(t *testing.T) {
	tests := []struct {
		name     string
		input    string
		expected string
	}{
		{
			name:     "AmpersandInContent",
			input:    `<doc>&amp;</doc>`,
			expected: `<doc>&amp;</doc>`,
		},
		{
			name:     "LessThanInContent",
			input:    `<doc>&lt;</doc>`,
			expected: `<doc>&lt;</doc>`,
		},
		{
			name:     "GreaterThanInContent",
			input:    `<doc>&gt;</doc>`,
			expected: `<doc>&gt;</doc>`,
		},
		{
			name:     "QuoteInAttrDoubleQuoted",
			input:    `<doc attr="he said &quot;hi&quot;"/>`,
			expected: `<doc attr="he said &quot;hi&quot;"></doc>`,
		},
		{
			name:     "AmpersandInAttr",
			input:    `<doc attr="a&amp;b"/>`,
			expected: `<doc attr="a&amp;b"></doc>`,
		},
		{
			name:     "LessThanInAttr",
			input:    `<doc attr="a&lt;b"/>`,
			expected: `<doc attr="a&lt;b"></doc>`,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			doc := etree.NewDocument()
			if err := doc.ReadFromString(tt.input); err != nil {
				t.Fatal(err)
			}

			c := MakeC14N10ExclusiveCanonicalizerWithPrefixList("")
			got, err := c.Canonicalize(doc.Root())
			if err != nil {
				t.Fatal(err)
			}

			if string(got) != tt.expected {
				t.Errorf("expected: %s\ngot:      %s", tt.expected, string(got))
			}
		})
	}
}

// TestW3CC14NNamespaceRedeclaration verifies correct handling of namespace
// prefix redeclarations across element boundaries.
func TestW3CC14NNamespaceRedeclaration(t *testing.T) {
	// When a prefix is rebound to a different URI, the new binding must appear.
	input := `<root xmlns:p="http://first"><a xmlns:p="http://second"><p:b/></a></root>`

	t.Run("C14N11", func(t *testing.T) {
		doc := etree.NewDocument()
		if err := doc.ReadFromString(input); err != nil {
			t.Fatal(err)
		}

		c := MakeC14N11Canonicalizer()
		got, err := c.Canonicalize(doc.Root())
		if err != nil {
			t.Fatal(err)
		}

		// In C14N 1.1, the redeclaration must appear on <a>
		result := string(got)
		if !strings.Contains(result, `xmlns:p="http://second"`) {
			t.Errorf("expected namespace redeclaration to appear\ngot: %s", result)
		}
	})

	t.Run("ExcC14N", func(t *testing.T) {
		doc := etree.NewDocument()
		if err := doc.ReadFromString(input); err != nil {
			t.Fatal(err)
		}

		c := MakeC14N10ExclusiveCanonicalizerWithPrefixList("")
		got, err := c.Canonicalize(doc.Root())
		if err != nil {
			t.Fatal(err)
		}

		result := string(got)
		// In exc-c14n, p: is only used on <p:b>, so the binding goes there
		if !strings.Contains(result, `<p:b xmlns:p="http://second">`) {
			t.Errorf("expected namespace on p:b element\ngot: %s", result)
		}
	})
}

// TestW3CC14NSuperfluous verifies that redundant namespace re-declarations are
// stripped in inclusive canonicalization.
func TestW3CC14NSuperfluous(t *testing.T) {
	input := `<a:foo xmlns:a="http://a">
 <a:bar xmlns:a="http://a">
  <a:baz xmlns:a="http://a"/>
 </a:bar>
</a:foo>`

	// The inner xmlns:a declarations are redundant and should be stripped.
	expected := `<a:foo xmlns:a="http://a">
 <a:bar>
  <a:baz></a:baz>
 </a:bar>
</a:foo>`

	methods := []struct {
		name  string
		makeC func() Canonicalizer
	}{
		{"C14N11", func() Canonicalizer { return MakeC14N11Canonicalizer() }},
		{"C14N10", func() Canonicalizer { return MakeC14N10RecCanonicalizer() }},
	}

	for _, m := range methods {
		t.Run(m.name, func(t *testing.T) {
			doc := etree.NewDocument()
			if err := doc.ReadFromString(input); err != nil {
				t.Fatal(err)
			}

			c := m.makeC()
			got, err := c.Canonicalize(doc.Root())
			if err != nil {
				t.Fatal(err)
			}

			if string(got) != expected {
				t.Errorf("expected:\n%s\ngot:\n%s", expected, string(got))
			}
		})
	}
}

// TestW3CC14NStartEndTags tests the W3C C14N 1.0 spec Section 3.3 example:
// normalization of start/end tags, attribute quoting, and empty elements.
func TestW3CC14NStartEndTags(t *testing.T) {
	input := `<doc>
   <e1   />
   <e2   ></e2>
   <e3   name = "elem3"   id="elem3"   />
   <e4   name="elem4"   id="elem4"   ></e4>
   <e5 a:attr="out" b:attr="sorted" attr2="all" attr="I'm"
      xmlns:b="http://www.ietf.org"
      xmlns:a="http://www.w3.org"
      xmlns="http://example.org"/>
   <e6 xmlns="" xmlns:a="http://www.w3.org">
      <e7 xmlns="http://www.ietf.org">
         <e8 xmlns="" xmlns:a="http://www.w3.org">
            <e9 xmlns="" xmlns:a="http://www.ietf.org"/>
         </e8>
      </e7>
   </e6>
</doc>`

	// Expected C14N 1.0 output from the spec (and verified with xmllint)
	expected := `<doc>
   <e1></e1>
   <e2></e2>
   <e3 id="elem3" name="elem3"></e3>
   <e4 id="elem4" name="elem4"></e4>
   <e5 xmlns="http://example.org" xmlns:a="http://www.w3.org" xmlns:b="http://www.ietf.org" attr="I'm" attr2="all" b:attr="sorted" a:attr="out"></e5>
   <e6 xmlns:a="http://www.w3.org">
      <e7 xmlns="http://www.ietf.org">
         <e8 xmlns="">
            <e9 xmlns:a="http://www.ietf.org"></e9>
         </e8>
      </e7>
   </e6>
</doc>`

	methods := []struct {
		name     string
		makeC    func() Canonicalizer
		expected string
	}{
		{"C14N10", func() Canonicalizer { return MakeC14N10RecCanonicalizer() }, expected},
		{"C14N11", func() Canonicalizer { return MakeC14N11Canonicalizer() }, expected},
	}

	for _, m := range methods {
		t.Run(m.name, func(t *testing.T) {
			doc := etree.NewDocument()
			if err := doc.ReadFromString(input); err != nil {
				t.Fatal(err)
			}

			c := m.makeC()
			got, err := c.Canonicalize(doc.Root())
			if err != nil {
				t.Fatal(err)
			}

			if string(got) != m.expected {
				t.Errorf("C14N output differs from spec\n"+
					"--- expected ---\n%s\n"+
					"--- got ---\n%s\n"+
					"--- diff ---\n%s",
					m.expected, string(got), diffStrings(m.expected, string(got)))
			}
		})
	}
}

// TestW3CExcC14NInclusiveNamespaces tests the InclusiveNamespaces PrefixList
// parameter of exclusive canonicalization.
func TestW3CExcC14NInclusiveNamespaces(t *testing.T) {
	// When a prefix is in the InclusiveNamespaces list, it should be treated
	// like inclusive canonicalization (inherited from ancestors).
	input := `<n0:local xmlns:n0="foo:bar" xmlns:n3="ftp://example.org">
 <n1:elem2 xmlns:n1="http://example.net" xml:lang="en">
  <n3:stuff xmlns:n3="ftp://example.org"/>
 </n1:elem2>
</n0:local>`

	tests := []struct {
		name       string
		prefixList string
		contains   []string
		notContains []string
	}{
		{
			name:       "NoPrefixes",
			prefixList: "",
			// n3 only visibly used on <n3:stuff>, so pushed down there
			contains:   []string{`<n3:stuff xmlns:n3="ftp://example.org"`},
		},
		{
			name:       "IncludeN3",
			prefixList: "n3",
			// n3 is now inclusive, so it should appear on the root
			contains:   []string{`xmlns:n3="ftp://example.org"`},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			doc := etree.NewDocument()
			if err := doc.ReadFromString(input); err != nil {
				t.Fatal(err)
			}

			c := MakeC14N10ExclusiveCanonicalizerWithPrefixList(tt.prefixList)
			got, err := c.Canonicalize(doc.Root())
			if err != nil {
				t.Fatal(err)
			}

			result := string(got)
			for _, s := range tt.contains {
				if !strings.Contains(result, s) {
					t.Errorf("expected output to contain %q\ngot: %s", s, result)
				}
			}
			for _, s := range tt.notContains {
				if strings.Contains(result, s) {
					t.Errorf("expected output NOT to contain %q\ngot: %s", s, result)
				}
			}
		})
	}
}

// TestW3CC14NXmlAttributes tests handling of xml: prefixed attributes
// (xml:lang, xml:space, etc.)
func TestW3CC14NXmlAttributes(t *testing.T) {
	input := `<doc xml:lang="en" xml:space="preserve">
 <p xml:lang="fr">Bonjour</p>
 <p>Hello</p>
</doc>`

	methods := []struct {
		name  string
		makeC func() Canonicalizer
	}{
		{"ExcC14N", func() Canonicalizer { return MakeC14N10ExclusiveCanonicalizerWithPrefixList("") }},
		{"C14N11", func() Canonicalizer { return MakeC14N11Canonicalizer() }},
		{"C14N10", func() Canonicalizer { return MakeC14N10RecCanonicalizer() }},
	}

	for _, m := range methods {
		t.Run(m.name, func(t *testing.T) {
			doc := etree.NewDocument()
			if err := doc.ReadFromString(input); err != nil {
				t.Fatal(err)
			}

			c := m.makeC()
			got, err := c.Canonicalize(doc.Root())
			if err != nil {
				t.Fatal(err)
			}

			result := string(got)
			// xml:lang and xml:space should be preserved
			if !strings.Contains(result, `xml:lang="en"`) {
				t.Errorf("missing xml:lang on doc: %s", result)
			}
			if !strings.Contains(result, `xml:lang="fr"`) {
				t.Errorf("missing xml:lang on p: %s", result)
			}
			if !strings.Contains(result, `xml:space="preserve"`) {
				t.Errorf("missing xml:space: %s", result)
			}
		})
	}
}

// TestW3CC14NUnicodeContent verifies that Unicode content is preserved through
// canonicalization.
func TestW3CC14NUnicodeContent(t *testing.T) {
	input := `<doc><text>日本語テスト</text><text>Ñoño</text></doc>`

	doc := etree.NewDocument()
	if err := doc.ReadFromString(input); err != nil {
		t.Fatal(err)
	}

	c := MakeC14N10ExclusiveCanonicalizerWithPrefixList("")
	got, err := c.Canonicalize(doc.Root())
	if err != nil {
		t.Fatal(err)
	}

	result := string(got)
	if !strings.Contains(result, "日本語テスト") {
		t.Errorf("Japanese text not preserved: %s", result)
	}
	if !strings.Contains(result, "Ñoño") {
		t.Errorf("Spanish text not preserved: %s", result)
	}
}

// TestC14NIdempotency verifies that canonicalizing an already-canonical document
// produces identical output (idempotency property).
func TestC14NIdempotency(t *testing.T) {
	inputs := []string{
		`<doc><a/><b attr="val"/></doc>`,
		`<root xmlns:a="http://a" xmlns:b="http://b"><a:x b:y="z"/></root>`,
		`<doc xml:lang="en"><p>text &amp; more</p></doc>`,
		`<a xmlns="http://default"><b><c/></b></a>`,
	}

	methods := []struct {
		name  string
		makeC func() Canonicalizer
	}{
		{"ExcC14N", func() Canonicalizer { return MakeC14N10ExclusiveCanonicalizerWithPrefixList("") }},
		{"C14N11", func() Canonicalizer { return MakeC14N11Canonicalizer() }},
		{"C14N10", func() Canonicalizer { return MakeC14N10RecCanonicalizer() }},
	}

	for _, input := range inputs {
		for _, m := range methods {
			t.Run(m.name, func(t *testing.T) {
				// First pass
				doc1 := etree.NewDocument()
				if err := doc1.ReadFromString(input); err != nil {
					t.Fatal(err)
				}
				pass1, err := m.makeC().Canonicalize(doc1.Root())
				if err != nil {
					t.Fatal(err)
				}

				// Second pass: canonicalize the canonical output
				doc2 := etree.NewDocument()
				if err := doc2.ReadFromBytes(pass1); err != nil {
					t.Fatalf("failed to re-parse canonical output: %v", err)
				}
				pass2, err := m.makeC().Canonicalize(doc2.Root())
				if err != nil {
					t.Fatal(err)
				}

				if string(pass1) != string(pass2) {
					t.Errorf("C14N not idempotent\npass1: %s\npass2: %s", string(pass1), string(pass2))
				}
			})
		}
	}
}

// diffStrings produces a simple line-by-line diff for error messages.
func diffStrings(expected, got string) string {
	expLines := strings.Split(expected, "\n")
	gotLines := strings.Split(got, "\n")

	var b strings.Builder
	max := len(expLines)
	if len(gotLines) > max {
		max = len(gotLines)
	}

	for i := 0; i < max; i++ {
		var exp, g string
		if i < len(expLines) {
			exp = expLines[i]
		}
		if i < len(gotLines) {
			g = gotLines[i]
		}
		if exp != g {
			b.WriteString("  expected: " + exp + "\n")
			b.WriteString("  got:      " + g + "\n")
		}
	}
	return b.String()
}
